func (a *adapter) CreateFoo(ctx context.Context, input billing.CreateFooInput) (*billing.Foo, error) {
    if err := input.Validate(); err != nil {
        return nil, billing.ValidationError{Err: err}
    }
    return entutils.TransactingRepo(ctx, a, func(ctx context.Context, tx *adapter) (*billing.Foo, error) {
        row, err := tx.db.BillingFoo.Create().
            SetNamespace(input.Namespace).
            SetName(input.Name).
            Save(ctx)
        if err != nil {
            return nil, err
        }
        return mapFooFromDB(row), nil
    })
}

type (
    FooRequest  = billing.FooInput
    FooResponse = api.BillingFoo
    FooParams   struct{ ID string }
    FooHandler  httptransport.HandlerWithArgs[FooRequest, FooResponse, FooParams]
)

func (h *handler) Foo() FooHandler {
    return httptransport.NewHandlerWithArgs(
        func(ctx context.Context, r *http.Request, p FooParams) (FooRequest, error) {
            ns, err := h.resolveNamespace(ctx)
            if err != nil { return FooRequest{}, fmt.Errorf("namespace: %w", err) }
            return billing.FooInput{Namespace: ns, ID: p.ID}, nil
        },
        func(ctx context.Context, req FooRequest) (FooResponse, error) {
            result, err := h.service.Foo(ctx, req)
            if err != nil { return FooResponse{}, err }
            return mapFooToAPI(result), nil
        },
        commonhttp.JSONResponseEncoderWithStatus[FooResponse](http.StatusOK),
        httptransport.AppendOptions(
            h.options,
            httptransport.WithOperationName("Foo"),
            httptransport.WithErrorEncoder(errorEncoder()),
        )...,
    )
}

func (e *Engine) OnCollectionCompleted(ctx context.Context, input billing.OnCollectionCompletedInput) (billing.StandardLines, error) {
    // Guard: skip if already snapshotted at or after collection time
    if input.Invoice.QuantitySnapshotedAt != nil &&
        !input.Invoice.QuantitySnapshotedAt.Before(input.Invoice.DefaultCollectionAtForStandardInvoice()) {
        return input.Lines, nil
    }
    if err := e.quantitySnapshotter.SnapshotLineQuantities(ctx, input.Invoice, input.Lines); err != nil {
        if _, isInvalidDatabaseState := lo.ErrorsAs[*billing.ErrSnapshotInvalidDatabaseState](err); isInvalidDatabaseState {
            return nil, billing.ValidationIssue{
                Severity:  billing.ValidationIssueSeverityCritical,
                Code:      billing.ErrInvoiceLineSnapshotFailed.Code,
                Message:   err.Error(),
                Component: billing.ValidationComponentOpenMeterMetering,
            }
        }
        return nil, fmt.Errorf("snapshotting lines: %w", err)
    }
    return input.Lines, nil
}

import "github.com/openmeterio/openmeter/openmeter/billing/testutils"

type captureEngine struct {
    testutils.NoopLineEngine
    captured billing.StandardLines
}

func (e *captureEngine) OnCollectionCompleted(_ context.Context, input billing.OnCollectionCompletedInput) (billing.StandardLines, error) {
    e.captured = input.Lines
    return input.Lines, nil
}

